private function replaceGoldPricePlaceholders($content) {
	$fallbacks = array(
		'583' => array(870000, 1500000),
		'585' => array(870000, 1000000),
		'750' => array(1120000, 1500000),
		'850' => array(1260000, 1400000),
		'875' => array(1300000, 1400000),
		'916' => array(1360000, 1500000),
		'999' => array(1490000, 1600000)
	);
	$latest = array();
	$table_query = $this->db->query("SHOW TABLES LIKE 'diamant_gold_prices'");

	if ($table_query->num_rows) {
		$query = $this->db->query("SELECT * FROM `diamant_gold_prices` ORDER BY `id` DESC LIMIT 1");
		$latest = $query->row;
	}

	$ranges = array();
	foreach ($fallbacks as $probe => $fallback) {
		$from_key = 'price_' . $probe . '_from';
		$to_key = 'price_' . $probe . '_to';
		$from = isset($latest[$from_key]) ? (int)$latest[$from_key] : $fallback[0];
		$to = isset($latest[$to_key]) ? (int)$latest[$to_key] : $fallback[1];
		$ranges[$probe] = number_format($from, 0, '', ' ') . ' - ' . number_format($to, 0, '', ' ');
		$content = str_replace('{{gold_price_' . $probe . '}}', $ranges[$probe], $content);
	}

	$content = str_replace('{{gold_price_crowns}}', $ranges['850'], $content);
	$content = str_replace('{{gold_prices_updated_at}}', isset($latest['created_at']) ? $latest['created_at'] : '', $content);

	return $content;
}
